module RefModule(
    input A,
    input B,
    input C,
    input D,
    output Y
);wire and_gate_out;
    wire or_gate_out;

    // AND gate implementation
  wire temp1_A & B = A & B;
  wire temp2_C = C;
  assign and_gate_out = temp1_A & B & temp2_C;

    // OR gate implementation
    assign or_gate_out = A | B;

    // Final output implementation
    assign Y = and_gate_out | D | or_gate_out;

endmodule
